import React from "react";
import Header from "../components/Header";

export default function Portfolio() {
  return (
    <div style={{ background: "#F3F6FC", minHeight: "100vh" }}>
      <Header />
      <div style={{ maxWidth: 900, margin: "0 auto", padding: "2rem 1rem" }}>
        <h2
          style={{
            color: "#5D5FEF",
            fontWeight: 700,
            fontSize: 24,
            marginBottom: 24,
          }}
        >
          User Portfolio
        </h2>
        <p style={{ color: "#888", fontSize: 16 }}>
          This section displays the user's investment/borrowing performance,
          returns, and any key metrics or graphs as per the visual mockup.
          (Implement graphs as needed)
        </p>
      </div>
    </div>
  );
}
